import "./toolbar.css";

import { Toolbar } from "radix-ui";
import { cn } from "tailwind-variants";

import { ToolbarContext } from "./toolbar.context";
import { toolbarVariants } from "./toolbar.variants";

export type ToolbarRootProps = React.ComponentProps<typeof Toolbar.Root>;

export const ToolbarRoot = ({ className, ...props }: ToolbarRootProps) => {
  const slots = toolbarVariants();

  return (
    <ToolbarContext value={{ slots }}>
      <Toolbar.Root className={cn(slots.root(), className)} {...props} />
    </ToolbarContext>
  );
};

import { Toolbar } from "radix-ui";

export type ToolbarToggleGroupProps = React.ComponentProps<typeof Toolbar.ToggleGroup>;

export const ToolbarToggleGroup = (props: ToolbarToggleGroupProps) => {
  return <Toolbar.ToggleGroup {...props} />;
};

import { Toolbar } from "radix-ui";
import { cn } from "tailwind-variants";

import { useToolbarContext } from "./toolbar.context";

export type ToolbarToggleItemProps = React.ComponentProps<typeof Toolbar.ToggleItem>;

export const ToolbarToggleItem = ({ className, ...props }: ToolbarToggleItemProps) => {
  const { slots } = useToolbarContext();

  return <Toolbar.ToggleItem className={cn(slots.toggleItem(), className)} {...props} />;
};

import { Toolbar } from "radix-ui";
import { cn } from "tailwind-variants";

import { useToolbarContext } from "./toolbar.context";

export type ToolbarSeparatorProps = React.ComponentProps<typeof Toolbar.Separator>;

export const ToolbarSeparator = ({ className, ...props }: ToolbarSeparatorProps) => {
  const { slots } = useToolbarContext();

  return <Toolbar.Separator className={cn(slots.separator(), className)} {...props} />;
};

import { Toolbar } from "radix-ui";
import { cn } from "tailwind-variants";

import { useToolbarContext } from "./toolbar.context";

export type ToolbarLinkProps = React.ComponentProps<typeof Toolbar.Link>;

export const ToolbarLink = ({ className, ...props }: ToolbarLinkProps) => {
  const { slots } = useToolbarContext();

  return <Toolbar.Link className={cn(slots.link(), className)} {...props} />;
};

import { Toolbar } from "radix-ui";
import { cn } from "tailwind-variants";

import { useToolbarContext } from "./toolbar.context";

export type ToolbarButtonProps = React.ComponentProps<typeof Toolbar.Button>;

export const ToolbarButton = ({ className, ...props }: ToolbarButtonProps) => {
  const { slots } = useToolbarContext();

  return <Toolbar.Button className={cn(slots.button(), className)} {...props} />;
};

import { createContext, useContext } from "react";

import { toolbarVariants } from "./toolbar.variants";

export type ToolbarContext = {
  slots: ReturnType<typeof toolbarVariants>;
};

export const ToolbarContext = createContext<null | ToolbarContext>(null);

export const useToolbarContext = () => {
  const context = useContext(ToolbarContext);
  if (!context) {
    throw new Error("useToolbarContext must be used within a Toolbar");
  }
  return context;
};

import { tv, type VariantProps } from "tailwind-variants";

export const toolbarVariants = tv({
  slots: {
    button: "toolbar__button",
    link: "toolbar__link",
    root: "toolbar",
    separator: "toolbar__separator",
    toggleItem: "toolbar__toggle-item",
  },
});

export type ToolbarVariants = VariantProps<typeof toolbarVariants>;

.toolbar {
  @apply bg-background flex w-full items-center gap-1 rounded-md border p-1;
}

.toolbar__toggle-item {
  @apply inline-flex size-8 items-center justify-center rounded-md text-sm transition-colors;

  &:hover {
    @apply bg-muted text-muted-foreground;
  }

  &:focus-visible {
    @apply outline-ring outline-2 outline-offset-2;
  }

  &[data-state="on"] {
    @apply bg-accent text-accent-foreground;
  }
}

.toolbar__separator {
  @apply bg-border mx-1 h-6 w-px;
}

.toolbar__link {
  @apply text-muted-foreground inline-flex items-center justify-center rounded-md px-2 py-1 text-sm no-underline transition-colors;

  &:hover {
    @apply bg-muted text-foreground;
  }

  &:focus-visible {
    @apply outline-ring outline-2 outline-offset-2;
  }
}

.toolbar__button {
  @apply bg-primary text-primary-foreground ml-auto inline-flex h-8 items-center justify-center rounded-md px-3 text-sm font-medium transition-colors;

  &:hover {
    @apply bg-primary/90;
  }

  &:focus-visible {
    @apply outline-ring outline-2 outline-offset-2;
  }
}

import { ToolbarButton } from "./toolbar-button";
import { ToolbarLink } from "./toolbar-link";
import { ToolbarRoot } from "./toolbar-root";
import { ToolbarSeparator } from "./toolbar-separator";
import { ToolbarToggleGroup } from "./toolbar-toggle-group";
import { ToolbarToggleItem } from "./toolbar-toggle-item";

export const Toolbar = {
  Button: ToolbarButton,
  Link: ToolbarLink,
  Root: ToolbarRoot,
  Separator: ToolbarSeparator,
  ToggleGroup: ToolbarToggleGroup,
  ToggleItem: ToolbarToggleItem,
};

export {
  ToolbarButton,
  ToolbarLink,
  ToolbarRoot,
  ToolbarSeparator,
  ToolbarToggleGroup,
  ToolbarToggleItem,
};

export { ToolbarContext, useToolbarContext } from "./toolbar.context";

export { type ToolbarVariants, toolbarVariants } from "./toolbar.variants";
